public struct ConnectionResultFfi {
    public var reasonCode: UInt8
    public var sessionPresent: Bool

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(reasonCode: UInt8, sessionPresent: Bool) {
        self.reasonCode = reasonCode
        self.sessionPresent = sessionPresent
    }
}



extension ConnectionResultFfi: Equatable, Hashable {
    public static func ==(lhs: ConnectionResultFfi, rhs: ConnectionResultFfi) -> Bool {
        if lhs.reasonCode != rhs.reasonCode {
            return false
        }
        if lhs.sessionPresent != rhs.sessionPresent {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(reasonCode)
        hasher.combine(sessionPresent)
    }
}


