// Note that we don't yet support `indirect` for enums.
// See https://github.com/mozilla/uniffi-rs/issues/396 for further discussion.

public enum MqttEventFfi {
    
    case connected(ConnectionResultFfi
    )
    case disconnected(reasonCode: UInt8?
    )
    case messageReceived(MqttMessageFfi
    )
    case published(PublishResultFfi
    )
    case subscribed(SubscribeResultFfi
    )
    case unsubscribed(UnsubscribeResultFfi
    )
    case pingResponse(success: Bool
    )
    case error(message: String
    )
    case reconnectNeeded
    case reconnectScheduled(attempt: UInt32, delayMs: UInt64
    )
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMqttEventFFI: FfiConverterRustBuffer {
    typealias SwiftType = MqttEventFfi

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> MqttEventFfi {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .connected(try FfiConverterTypeConnectionResultFFI.read(from: &buf)
        )
        
        case 2: return .disconnected(reasonCode: try FfiConverterOptionUInt8.read(from: &buf)
        )
        
        case 3: return .messageReceived(try FfiConverterTypeMqttMessageFFI.read(from: &buf)
        )
        
        case 4: return .published(try FfiConverterTypePublishResultFFI.read(from: &buf)
        )
        
        case 5: return .subscribed(try FfiConverterTypeSubscribeResultFFI.read(from: &buf)
        )
        
        case 6: return .unsubscribed(try FfiConverterTypeUnsubscribeResultFFI.read(from: &buf)
        )
        
        case 7: return .pingResponse(success: try FfiConverterBool.read(from: &buf)
        )
        
        case 8: return .error(message: try FfiConverterString.read(from: &buf)
        )
        
        case 9: return .reconnectNeeded
        
        case 10: return .reconnectScheduled(attempt: try FfiConverterUInt32.read(from: &buf), delayMs: try FfiConverterUInt64.read(from: &buf)
        )
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: MqttEventFfi, into buf: inout [UInt8]) {
        switch value {
        
        
        case let .connected(v1):
            writeInt(&buf, Int32(1))
            FfiConverterTypeConnectionResultFFI.write(v1, into: &buf)
            
        
        case let .disconnected(reasonCode):
            writeInt(&buf, Int32(2))
            FfiConverterOptionUInt8.write(reasonCode, into: &buf)
            
        
        case let .messageReceived(v1):
            writeInt(&buf, Int32(3))
            FfiConverterTypeMqttMessageFFI.write(v1, into: &buf)
            
        
        case let .published(v1):
            writeInt(&buf, Int32(4))
            FfiConverterTypePublishResultFFI.write(v1, into: &buf)
            
        
        case let .subscribed(v1):
            writeInt(&buf, Int32(5))
            FfiConverterTypeSubscribeResultFFI.write(v1, into: &buf)
            
        
        case let .unsubscribed(v1):
            writeInt(&buf, Int32(6))
            FfiConverterTypeUnsubscribeResultFFI.write(v1, into: &buf)
            
        
        case let .pingResponse(success):
            writeInt(&buf, Int32(7))
            FfiConverterBool.write(success, into: &buf)
            
        
        case let .error(message):
            writeInt(&buf, Int32(8))
            FfiConverterString.write(message, into: &buf)
            
        
        case .reconnectNeeded:
            writeInt(&buf, Int32(9))
        
        
        case let .reconnectScheduled(attempt,delayMs):
            writeInt(&buf, Int32(10))
            FfiConverterUInt32.write(attempt, into: &buf)
            FfiConverterUInt64.write(delayMs, into: &buf)
            
        }
    }
}


